External knowledge: 
- Overall performance is the sum of test scores, mid-term scores, and final scores; 
- Rank is assigned based on overall performance in descending order (i.e., the highest scorer gets rank 1).

sql:
SELECT final_score
FROM finals
WHERE final_score > 30;

SELECT first_name
FROM students
WHERE student_id = '1';

external_knowledge:
; In academic contexts, a major refers to a student's field of study; 
; A department refers to the academic division offering a course; 
; The query aims to find a correlation between a student's major and their performance in courses offered by the corresponding department.

sql:
SELECT test_score
FROM class_tests
WHERE enrollment_id = '1';

SELECT grade
FROM student_courses
WHERE enrollment_id = '0';
